411: // getPanels extracts all panels from the dashboard (including nested panels)
412: // This matches the frontend's depth-first iteration order in panelIterator()
413: func getPanels(dashboard map[string]interface{}) []map[string]interface{} {
414: 	var panels []map[string]interface{}
415: 
416: 	// Get top-level panels
417: 	if dashboardPanels, ok := dashboard["panels"].([]interface{}); ok {
418: 		for _, panelInterface := range dashboardPanels {
419: 			if panel, ok := panelInterface.(map[string]interface{}); ok {
420: 				// Add top-level panel first
421: 				panels = append(panels, panel)
422: 
423: 				// Then add its nested panels (depth-first order)
424: 				if nestedPanels, ok := panel["panels"].([]interface{}); ok {
425: 					for _, nestedPanelInterface := range nestedPanels {
426: 						if nestedPanel, ok := nestedPanelInterface.(map[string]interface{}); ok {
427: 							panels = append(panels, nestedPanel)
428: 						}
429: 					}
430: 				}
431: 			}
432: 		}
433: 	}
434: 
435: 	return panels
436: }
