438: // cleanupPanelForSaveWithContext mimics the PanelModel.getSaveModel() behavior
439: // This removes properties that shouldn't be persisted and filters out default values
440: func cleanupPanelForSaveWithContext(panel map[string]interface{}, isNested bool) {
441: 	// Apply auto-migration logic (matches frontend PanelModel constructor)
442: 	// This happens during cleanup phase to match when frontend applies auto-migration
443: 	// Only apply auto-migration to top-level panels, not nested ones (matches frontend behavior)
444: 	if !isNested {
445: 		applyPanelAutoMigration(panel)
446: 	}
447: 
448: 	// Library panel specific cleanup (matches frontend behavior)
449: 	// Frontend only preserves id, title, gridPos, and libraryPanel for library panels
450: 	if libraryPanel, hasLibraryPanel := panel["libraryPanel"]; hasLibraryPanel && libraryPanel != nil {
451: 		// Create a new panel with only the essential properties
452: 		essentialProps := map[string]interface{}{
453: 			"id":           panel["id"],
454: 			"title":        panel["title"],
455: 			"gridPos":      panel["gridPos"],
456: 			"libraryPanel": libraryPanel,
457: 		}
458: 
459: 		// Clear the original panel and copy back only essential properties
460: 		for key := range panel {
461: 			delete(panel, key)
462: 		}
463: 		for key, value := range essentialProps {
464: 			if value != nil {
465: 				panel[key] = value
466: 			}
467: 		}
468: 		return // Skip the rest of the cleanup for library panels
469: 	}
470: 
471: 	// Row panel specific cleanup (matches frontend behavior)
472: 	cleanupRowPanelProperties(panel)
473: 
474: 	// Track which properties were present in the input to preserve them even if they become empty
475: 	originalProperties := make(map[string]bool)
476: 	for key := range panel {
477: 		originalProperties[key] = true
478: 	}
479: 	// Properties that should never be persisted (notPersistedProperties)
480: 	notPersistedProps := map[string]bool{
481: 		"events":                  true,
482: 		"isViewing":               true,
483: 		"isEditing":               true,
484: 		"isInView":                true,
485: 		"hasRefreshed":            true,
486: 		"cachedPluginOptions":     true, // This is the key one causing issues
487: 		"plugin":                  true,
488: 		"queryRunner":             true,
489: 		"replaceVariables":        true,
490: 		"configRev":               true,
491: 		"hasSavedPanelEditChange": true,
492: 		"getDisplayTitle":         true,
493: 		"dataSupport":             true,
494: 		"key":                     true,
495: 		"isNew":                   true,
496: 		"refreshWhenInView":       true,
497: 		"scopedVars":              true, // Frontend removes scopedVars from save model
498: 	}
499: 
500: 	// Default values that should be filtered out if they match (defaults)
501: 	defaults := map[string]interface{}{
502: 		"gridPos": map[string]interface{}{
503: 			"x": float64(0), "y": float64(0), "h": float64(3), "w": float64(6),
504: 		},
505: 		"targets": []interface{}{
506: 			map[string]interface{}{"refId": "A"},
507: 		},
508: 		"cachedPluginOptions": map[string]interface{}{},
509: 		"transparent":         false,
510: 		"options":             map[string]interface{}{},
511: 		"links":               []interface{}{},
512: 		"fieldConfig": map[string]interface{}{
513: 			"defaults":  map[string]interface{}{},
514: 			"overrides": []interface{}{},
515: 		},
516: 		"title": "",
517: 	}
518: 
519: 	// Remove notPersistedProperties
520: 	for prop := range notPersistedProps {
521: 		delete(panel, prop)
522: 	}
523: 
524: 	// Filter out properties that match defaults
525: 	for prop, defaultValue := range defaults {
526: 		if panelValue, exists := panel[prop]; exists {
527: 			if isEqual(panelValue, defaultValue) {
528: 				delete(panel, prop)
529: 			}
530: 		}
531: 	}
532: 
533: 	// Remove empty transformations array unless nested panel had them originally
534: 	if transformations, ok := panel["transformations"].([]interface{}); ok && len(transformations) == 0 {
535: 		if panel["_originallyHadTransformations"] != true || !isNested {
536: 			delete(panel, "transformations")
537: 		}
538: 	}
539: 
540: 	// Remove null values recursively to match frontend's JSON.stringify/parse behavior
541: 	// Pass panel type information to help with threshold handling
542: 	panelType := ""
543: 	if t, ok := panel["type"].(string); ok {
544: 		panelType = t
545: 	}
546: 	removeNullValuesRecursivelyWithContext(panel, panelType)
547: 
548: 	// Filter out properties that match defaults (matches frontend's isEqual logic)
549: 	filterDefaultValues(panel, originalProperties)
550: 
551: 	// Clean up internal markers
552: 	delete(panel, "_originallyHadTransformations")
553: 	delete(panel, "_originallyHadFieldConfigCustom")
554: }
