664: // isEqual checks if two values are equal (simplified version)
665: func isEqual(a, b interface{}) bool {
666: 	if a == nil && b == nil {
667: 		return true
668: 	}
669: 	if a == nil || b == nil {
670: 		return false
671: 	}
672: 
673: 	// For simple types, use direct comparison
674: 	switch aVal := a.(type) {
675: 	case bool:
676: 		if bVal, ok := b.(bool); ok {
677: 			return aVal == bVal
678: 		}
679: 	case string:
680: 		if bVal, ok := b.(string); ok {
681: 			return aVal == bVal
682: 		}
683: 	case float64:
684: 		if bVal, ok := b.(float64); ok {
685: 			return aVal == bVal
686: 		}
687: 	case []interface{}:
688: 		if bVal, ok := b.([]interface{}); ok {
689: 			if len(aVal) != len(bVal) {
690: 				return false
691: 			}
692: 			for i, v := range aVal {
693: 				if !isEqual(v, bVal[i]) {
694: 					return false
695: 				}
696: 			}
697: 			return true
698: 		}
699: 	case map[string]interface{}:
700: 		if bVal, ok := b.(map[string]interface{}); ok {
